    if (@hasField(ruby.KeywordId, "OR_KW")) arr[@intFromEnum(ruby.KeywordId.OR_KW)] = 73;
    if (@hasField(ruby.KeywordId, "AND_KW")) arr[@intFromEnum(ruby.KeywordId.AND_KW)] = 74;
    if (@hasField(ruby.KeywordId, "ASSIGN")) arr[@intFromEnum(ruby.KeywordId.ASSIGN)] = 75;
    if (@hasField(ruby.KeywordId, "PLUS_EQ")) arr[@intFromEnum(ruby.KeywordId.PLUS_EQ)] = 76;
