    if (@hasField(ruby.KeywordId, "SLASH_EQ")) arr[@intFromEnum(ruby.KeywordId.SLASH_EQ)] = 79;
    if (@hasField(ruby.KeywordId, "PERCENT_EQ")) arr[@intFromEnum(ruby.KeywordId.PERCENT_EQ)] = 80;
